+  for (size_t i = 0; i < sample_count; i++) {
+    for (int shift = 0; shift < HotSpotNumerics::type_width<U>(); shift++) {
+      test_lshift_correctness_samples(samples[i], shift);
+      test_lshift_monotonicity_samples(samples[i], shift);
+    }
+  }
+}
